                    React.createElement(Sidebar, null,
                        React.createElement(Categories, { mode: mode || 'view', building_id: building_id }))),
                React.createElement(Route, { exact: true, path: "/multi-edit/:cat", render: (props) => (React.createElement(MultiEdit, { category: category, dataString: this.getMultiEditDataString(), user: this.props.user })) }),
                React.createElement(Route, { exact: true, path: "/:mode/:cat/:building?" },
                    React.createElement(Sidebar, null,
                        React.createElement(Categories, { mode: mode || 'view', building_id: building_id }),
                        React.createElement(BuildingView, { mode: viewEditMode, cat: category, building: this.state.building, building_like: this.state.building_like, user_verified: this.state.user_verified, selectBuilding: this.selectBuilding, user: this.props.user }))),
                React.createElement(Route, { exact: true, path: "/:mode/:cat/:building/history" },
                    React.createElement(Sidebar, null,
                        React.createElement(Categories, { mode: mode || 'view', building_id: building_id }),
                        React.createElement(EditHistory, { building: this.state.building }))),
                React.createElement(Route, { exact: true, path: "/:mode(view|edit|multi-edit)", render: props => (React.createElement(Redirect, { to: `/${props.match.params.mode}/categories` })) })),
            React.createElement(ColouringMap, { building: this.state.building, mode: mode || 'basic', category: category, revision_id: this.state.revision_id, selectBuilding: this.selectBuilding, colourBuilding: this.colourBuilding })));
    }
}
export default MapApp;
